return items.map(item => {
  const errMsg = item.json?.message || item.json?.error || 'Error desconocido';
  return {
    json: {
      codigo: 500,
      mensaje: 'Error interno al procesar el lead: ' + errMsg,
      data: null
    }
  };
});

return items.map(item => ({
  json: {
    codigo: 200,
    mensaje: 'Lead procesado correctamente',
    data: {
      id_negocio: item.json.id_negocio || null,
      accion: 'procesado'
    }
  }
}));

return items.map(item => {
  const raw = item.json.body || item.json || {};

  // Separar nombres_completos_persona en nombre y apellido
  const fullName = String(raw.nombres_completos_persona || '').trim();
  const words = fullName.split(/\s+/).filter(w => w.length > 0);
  let nombre = '';
  let apellido = '';

  if (words.length === 0) {
    nombre = '';
    apellido = '';
  } else if (words.length === 1) {
    nombre = words[0];
    apellido = '';
  } else {
    const splitPoint = Math.max(1, Math.floor(words.length / 2));
    nombre = words.slice(0, splitPoint).join(' ');
    apellido = words.slice(splitPoint).join(' ');
  }

  // Normalizar modalidad desde nombre_campania
  const campania = (raw.nombre_campania || '').trim().toUpperCase();

  const modalidadPOSGRADO = [
    'ADMISION POS', 'ATRACCION BECAS POS', 'ATRACCION POS',
    'CIERRE POS', 'RETENCION POS', 'ATRACCION FP', 'CIERRE FP'
  ];
  const modalidadMEL = [
    'ATRACCION BECAS MEL', 'ATRACCION MEL', 'CIERRE MEL',
    'INBOUND', 'INTERRUPCION TEMPORAL', 'REINGRESO ESPECIAL',
    'REINGRESO GENERAL', 'REMATRICULA', 'RETENCION MEL'
  ];
  const modalidadTEC = [
    'ATRACCION BECAS TEC', 'ATRACCION TEC', 'CIERRE TEC',
    'RETENCION TEC'
  ];

  let modalidad = '';
  if (modalidadPOSGRADO.includes(campania)) {
    modalidad = 'POSGRADO';
  } else if (modalidadMEL.includes(campania)) {
    modalidad = 'MODALIDAD EN LINEA';
  } else if (modalidadTEC.includes(campania)) {
    modalidad = 'TECNOLÓGICO';
  }

  return {
    json: {
      id_negocio: String(raw.id_negocio || '').trim(),
      id_interno_negocio: String(raw.id_interno_negocio || '').trim(),
      cedula: String(raw.id_persona || '').trim(),
      nombre: nombre,
      apellido: apellido,
      modalidad: modalidad,
      producto: String(raw.nombre_producto_interes || '').trim(),
      telefono1: String(raw.celular_persona || '').trim(),
      estado_flujo: 'PENDIENTE',
      tipo_solicitud: String(raw.tipo_solicitud || '').trim(),
      nombre_corto_campania: String(raw.nombre_corto_campania || '').trim()
    }
  };
});

return items.map(item => {
  const esc = function(s) { return String(s || '').replace(/'/g, "''"); };
  const esFiniquitar = String(item.json.tipo_solicitud || '').trim().toLowerCase() === 'finiquitar';

  const setClauses = [
    'id_interno_negocio = EXCLUDED.id_interno_negocio',
    'cedula = EXCLUDED.cedula',
    'nombre = EXCLUDED.nombre',
    'apellido = EXCLUDED.apellido',
    'modalidad = EXCLUDED.modalidad',
    'producto = EXCLUDED.producto',
    'telefono1 = EXCLUDED.telefono1',
    'nombre_corto_campania = EXCLUDED.nombre_corto_campania'
  ];
  if (esFiniquitar) setClauses.push("estado_flujo = 'FINALIZADO'");
  setClauses.push('updated_at = now()');

  item.json.query = `INSERT INTO public.utpl_registros (id_negocio, id_interno_negocio, cedula, nombre, apellido, modalidad, producto, telefono1, nombre_corto_campania, estado_flujo, updated_at) VALUES ('${esc(item.json.id_negocio)}', '${esc(item.json.id_interno_negocio)}', '${esc(item.json.cedula)}', '${esc(item.json.nombre)}', '${esc(item.json.apellido)}', '${esc(item.json.modalidad)}', '${esc(item.json.producto)}', '${esc(item.json.telefono1)}', '${esc(item.json.nombre_corto_campania)}', 'PENDIENTE', now()) ON CONFLICT (id_negocio) DO UPDATE SET ${setClauses.join(', ')} RETURNING id_negocio, estado_flujo;`;

  return item;
});

return items.map(item => ({
  json: {
    codigo: 401,
    mensaje: 'No autorizado: token x-api-auth invalido',
    data: null
  }
}));
